select @periodFrom as periodFrom, @yearFrom as yearFrom, @periodTo as periodTo, @yearTo as yearTo
exec rs_rptFinancialStructureAnalysis @periodFrom, @yearFrom, @periodTo, @yearTo, 1, @ma_dvcs, @form, @@language, @@userID, @@admin







      &OutlineEntry;

function active$VoucherFilter$(f) {
	f.add_onResponseComplete(on$Filter$ResponseComplete);
	var d = new Date();
  if (!f.getItemValue('periodFrom')) f.setItemValues('periodFrom, yearFrom, periodTo, yearTo', [d.getMonth() + 1, d.getFullYear(), d.getMonth() + 1, d.getFullYear()]);
  f.live(f.getItem('periodFrom'));
  changeLookupReadonly(f, 'ma_dvcs', true);
}
function close$VoucherFilter$(f) { try { f.remove_onResponseComplete(on$Filter$ResponseComplete); } catch (ex) {} }
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.grid;
  switch (context) {
    case 'Checking':
      var periodFrom = f.getItem('periodFrom').value, yearFrom = f.getItem('yearFrom').value;
      var periodTo = f.getItem('periodTo').value, yearTo = f.getItem('yearTo').value;
      var index = f.getItem('form').selectedIndex, y = f.getItem('form').options, formName = y[index].text;
      g._alterTitle = [null, [['%f1', formName, true], ['%pf', periodFrom, true], ['%yf', yearFrom, true], ['%pt', periodTo, true], ['%yt', yearTo, true]]];      
			g._periodFrom = f.getItemValue('periodFrom');
			g._yearFrom = f.getItemValue('yearFrom');
			g._periodTo = f.getItemValue('periodTo');
			g._yearTo = f.getItemValue('yearTo');
			g._unit = f.getItemValue('ma_dvcs');
			g._form = f.getItemValue('form');
			g._arrValue = new Array();
      g._finish = 0;
      break;
    default:
      break;
  }
}
function initForm(f) {
  var o = f.getItem('form'), value = f._itemValue.split(String.fromCharCode(255)), text = f._itemText.split(String.fromCharCode(255));
  for (var i = 0; i < value.length; i++) {
    o.options[i] = new Option(text[i], value[i]);
  }
}




